shape.script:
function getHandles(params) {
    let radius = params.radius;
    let width = radius;
    let height = radius;
    let offset = params.offset / 1000.0;
    return {
        r: [0, radius],
        o: [-width + (2*width*offset),0]
    }
}

function getPath(params) {
    let radius = params.radius;
    let offset = params.offset / 1000.0;
    let width = radius;
    let height = radius;
    let cw = 0.551915024494 * width;
    let ch = 0.551915024494 * height;
    return [
        {   // TOP
            in:[-cw,-height],
            p:[0,-height],
            out:[-cw + (2*cw*offset),-height],
        },
        {  // RIGHT
            in:[-width + (2*width*offset),-ch],
            p:[-width + (2*width*offset),0],
            out:[-width + (2*width*offset),ch]
        },
        {  // BOTTOM
            in:[-cw + (2*cw*offset),height],
            p:[0,height],
            out:[-cw,height]
        },
        {  // LEFT
            in:[-width,ch],
            p:[-width,0],
            out:[-width,-ch]
        },
        {closed:true}
    ];
}
